CTA='\n<section class="post-cta-block" style="margin:3rem 0 2rem;padding:2rem;background:#1a1a2e;border:1px solid #7a5c00;border-radius:8px;text-align:center;">\n<p style="color:#c8a84b;font-size:0.85rem;letter-spacing:0.1em;margin-bottom:0.5rem;">NEXT ACTION</p>\n<p style="color:#f5f0e8;font-size:1rem;margin-bottom:1.5rem;">この記事が役に立ったら、次のアクションへ</p>\n<div style="display:flex;flex-direction:column;gap:0.75rem;align-items:center;">\n<a href="https://www.youtube.com/@Hiroyavolley" target="_blank" rel="noopener" style="display:inline-block;background:#c8a84b;color:#1a1a2e;padding:0.75rem 2rem;border-radius:4px;text-decoration:none;font-weight:bold;width:260px;">YouTube で動画を見る</a>\n<a href="https://x.com/machikawahiroya" target="_blank" rel="noopener" style="display:inline-block;background:#000;color:#fff;padding:0.75rem 2rem;border-radius:4px;text-decoration:none;width:260px;border:1px solid #333;">X でフォローする</a>\n<a href="mailto:vb06mh@gmail.com" style="display:inline-block;border:1px solid #c8a84b;color:#c8a84b;padding:0.75rem 2rem;border-radius:4px;text-decoration:none;width:260px;">質問・感想を送る</a>\n</div>\n</section>\n'
GA='<!-- GA4 placeholder -->\n'
STORY='<section style="max-width:720px;margin:4rem auto;padding:0 1.5rem;"><p style="color:#c8a84b;font-size:0.8rem;letter-spacing:0.15em;">MY STORY</p><h2 style="color:#f5f0e8;font-size:1.4rem;margin-bottom:2.5rem;line-height:1.5;">なぜクレーンオペレーターがバレーNo.1を目指すのか</h2><div style="display:flex;gap:1.5rem;margin-bottom:2rem;"><div><h3 style="color:#c8a84b;">昼は現場、夜はコートへ</h3><p style="color:#aaa;line-height:1.9;">毎朝、クレーンのコックピットから香川の空を見上げる。重機を精密に操作する仕事は、バレーと同じだと気づいた。ミリ単位の感覚、状況判断、絶対に失敗できないプレッシャー。現場で磨いた集中力と精度が、コートでの自分を作っている。</p></div></div><div style="display:flex;gap:1.5rem;margin-bottom:2rem;"><div><h3 style="color:#c8a84b;">才能がないと言われた</h3><p style="color:#aaa;line-height:1.9;">173cm。特別なジャンプ力があるわけでも、幼い頃から英才教育を受けてきたわけでもない。それでも、やめなかった。継続だけが自分の武器だと信じて。</p></div></div><div style="display:flex;gap:1.5rem;margin-bottom:2rem;"><div><h3 style="color:#c8a84b;">継続だけが、才能に勝てる</h3><p style="color:#aaa;line-height:1.9;">コービー・ブライアントのMamba Mentalityを知ってから、考え方が変わった。才能のある人間が努力をやめた瞬間、継続してきた人間が追い越す。今日が人生で一番若い日——まだ間に合う。</p></div></div><div style="display:flex;gap:1.5rem;margin-bottom:2rem;"><div><h3 style="color:#c8a84b;">香川から、日本一へ</h3><p style="color:#aaa;line-height:1.9;">目標は日本一のソフトバレー選手になること。大きすぎると笑われても構わない。このブログとYouTubeは、その挑戦の記録だ。あなたの自分にもできるのきっかけになれれば——それが全て。</p></div></div></section>'
def rf(p):
    with open(p,'r',encoding='utf-8') as f: return f.read()
def wf(p,c):
    with open(p,'w',encoding='utf-8') as f: f.write(c)
def aogp(c,o):
    if 'og:type' in c: return c
    return c.replace('</head>',o+'\n</head>',1)
def acta(c):
    if 'post-cta-block' in c: return c
    m=re.search(r'(<a[^>]+blog\.html[^>]*>[^<]*<[^<]*/a>)',c)
    if m: return c[:m.start()]+CTA+c[m.start():]
    return c
u=[]
for fn,og in [('index.html','<meta property="og:type" content="website">\n<meta property="og:title" content="HIROYA VOLLEYBALL | 香川県バレー・ソフトバレー上達ブログ">\n<meta property="og:url" content="'+SITE+'/index.html">\n<meta property="og:image" content="'+IMG+'">\n<meta name="twitter:card" content="summary_large_image">\n<meta name="twitter:site" content="@machikawahiroya">'),('about.html','<meta property="og:type" content="profile">\n<meta property="og:title" content="町川大弥とは | クレーンオペレーターxバレー選手 | HIROYA MACHIKAWA">\n<meta property="og:url" content="'+SITE+'/about.html">\n<meta property="og:image" content="'+IMG+'">\n<meta name="twitter:card" content="summary_large_image">\n<meta name="twitter:site" content="@machikawahiroya">'),('blog.html','<meta property="og:type" content="website">\n<meta property="og:title" content="取組・理論・記録 | HIROYA VOLLEYBALL BLOG">\n<meta property="og:url" content="'+SITE+'/blog.html">\n<meta property="og:image" content="'+IMG+'">\n<meta name="twitter:card" content="summary_large_image">\n<meta name="twitter:site" content="@machikawahiroya">')]:
    p=os.path.join(BASE,fn)
    if not os.path.exists(p): continue
    c=aogp(rf(p),og)
    if fn=='about.html' and 'MY STORY' not in c:
        c=c.replace('<footer',STORY+'\n<footer',1)
    wf(p,c); u.append(fn)
for pid,d in POSTS.items():
    p=os.path.join(BASE,'posts',pid+'.html')
    if not os.path.exists(p): continue
    c=rf(p)
    og='<meta property="og:type" content="article">\n<meta property="og:title" content="'+d['title']+'">\n<meta property="og:description" content="'+d['desc']+'">\n<meta property="og:url" content="'+SITE+'/posts/'+pid+'.html">\n<meta property="og:image" content="'+IMG+'">\n<meta name="twitter:card" content="summary_large_image">\n<meta name="twitter:site" content="@machikawahiroya">'
    c=aogp(c,og)
    c=re.sub(r'<title>.*?</title>','<title>'+d['title']+'</title>',c,flags=re.DOTALL)
    dt='<meta name="description" content="'+d['desc']+'">'
    if 'name="description"' in c: c=re.sub(r'<meta name="description"[^>]*>',dt,c)
    else: c=c.replace('<title>',dt+'\n<title>',1)
    c=acta(c)
    wf(p,c); u.append(pid)
print('完了: '+str(len(u))+'件')
for x in u: print(' OK '+x)
